import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.CndDaRl3.js";const g=JSON.parse('{"title":"Local Database with PGLite","description":"","frontmatter":{},"headers":[],"relativePath":"fork/local-database-pglite.md","filePath":"fork/local-database-pglite.md","lastUpdated":1776310984000}'),o={name:"fork/local-database-pglite.md"};function l(n,e,d,r,h,c){return a(),s("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /react-starter-kit/fork/local-database-pglite.md for this page in Markdown format</div><h1 id="local-database-with-pglite" tabindex="-1">Local Database with PGLite <a class="header-anchor" href="#local-database-with-pglite" aria-label="Permalink to &quot;Local Database with PGLite&quot;">​</a></h1><p>To simplify local development and avoid the need for running a full PostgreSQL server (via Docker, Postgres.app, or Homebrew), this fork utilizes <a href="https://pglite.dev/" target="_blank" rel="noreferrer">PGlite</a> (<code>@electric-sql/pglite</code>) for local database storage.</p><h2 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">​</a></h2><p>PGlite is an embedded PostgreSQL engine that runs directly in Node.js/Bun. It writes database files to the local file system.</p><p>In this project, the local database is stored in the <code>.tmp/pglite</code> directory at the root of the workspace.</p><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><ol><li><p><strong>Environment Variables</strong>: The <code>.env</code> file configures the <code>DATABASE_URL</code> to point to the local <code>.tmp/pglite</code> directory instead of a standard <code>postgres://</code> connection string.</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DATABASE_URL=.tmp/pglite</span></span></code></pre></div></li><li><p><strong>Drizzle Config</strong>: <code>db/drizzle.config.ts</code> detects if the <code>DATABASE_URL</code> is a PGLite path (not starting with <code>postgres://</code>) and automatically switches the Drizzle dialect driver to <code>pglite</code>. It also resolves the <code>.tmp/pglite</code> path relative to the project root.</p></li><li><p><strong>API Development Server</strong>: <code>apps/api/dev.ts</code> has been updated so that when running the local dev server (<code>bun dev</code>), it connects to the PGLite database using the <code>@electric-sql/pglite</code> client and passes that instance to the tRPC context. This bypasses the default behavior which attempts to connect to Cloudflare Hyperdrive.</p></li><li><p><strong>Seeding</strong>: <code>db/scripts/seed.ts</code> automatically parses the non-postgres connection string and uses the PGLite client to run seed scripts correctly.</p></li></ol><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>You can interact with the local PGLite database using the standard <code>db</code> package scripts from the root of the project:</p><ul><li><strong>Push schema changes:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:push</span></span></code></pre></div></li><li><strong>Seed the database:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:seed</span></span></code></pre></div></li><li><strong>Run the local dev server</strong> (which will automatically use the PGLite database):<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div></li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li><p><strong>Resetting the Database</strong>: If you need to completely wipe your local database, you can simply delete the <code>.tmp/pglite</code> directory and re-run the push and seed commands.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .tmp/pglite</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:push</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:seed</span></span></code></pre></div></li><li><p><strong>Cloudflare Deployments</strong>: PGLite is only used for local development. When deployed, the workers will still use the <code>DATABASE_URL</code> to connect to Neon PostgreSQL via Cloudflare Hyperdrive, as the deployed environments use the values injected in <code>.dev.vars</code> or the Wrangler bindings.</p></li></ul>`,13)])])}const u=t(o,[["render",l]]);export{g as __pageData,u as default};
